I add a small debug log to the function `func (c *Container) State()`  like this:

```go
// State returns the current state of the container
func (c *Container) State() (define.ContainerStatus, error) {
	if !c.batched {
		elapsed := ElapsedMilli()
		c.lock.Lock()
		if elapsed() > 5000 {
			logrus.Warnf("xxxx: slow Container.State get lock, cost_ms=%v container_name=%v", elapsed(), c.Name())
		} else {
			logrus.Infof("xxxx: normal Container.State get lock, cost_ms=%v container_name=%v", elapsed(), c.Name())
		}
		defer c.lock.Unlock()

		if err := c.syncContainer(); err != nil {
			return define.ContainerStateUnknown, err
		}
	}
	return c.state.State, nil
}

func ElapsedMilli() func() int64 {
	start := time.Now()
	return func() int64 {
		return time.Since(start).Milliseconds()
	}
}
```

